const src = $input.first().json;
const body = src.body || src;
const quoteId = body.quoteId;
const technicianId = body.technicianId;
const adminToken = body.adminToken;

if (typeof quoteId !== 'number' || !Number.isFinite(quoteId) || quoteId <= 0) {
  throw new Error('quoteId debe ser un número positivo');
}
if (typeof technicianId !== 'number' || !Number.isFinite(technicianId) || technicianId <= 0) {
  throw new Error('technicianId debe ser un número positivo');
}
// adminToken is optional for now (simple shared-secret pattern, validated if provided)
return [{ json: { quoteId: Math.floor(quoteId), technicianId: Math.floor(technicianId), adminToken: adminToken || null } }];

// Store the updated quote data for later use in Build response
const validated = $('Validate').first().json;
const row = $input.first().json;
if (!row || !row.id) {
  throw new Error('Cotización no encontrada o ya procesada');
}
return [{ json: { quoteId: row.id, techToken: row.tech_token, clientName: row.client_name, clientPhone: row.client_phone, technicianId: validated.technicianId } }];

const quoteData = $('Merge quote data').first().json;
const tech = $('Get technician').first().json || {};
return [{ json: { ok: true, quoteId: quoteData.quoteId, techToken: quoteData.techToken, techName: tech.name || null } }];
